163				Dependencies: append([]bead.Dependency(nil), b.Dependencies...),
164			},
165			ExecuteBead: report,
166			ProjectRoot: projectRoot,
167		}
168		if len(b.Extra) > 0 {
169			env.Bead.Extra = make(map[string]any, len(b.Extra))
170			for k, v := range b.Extra {
171				if k == "events" || k == "events_attachment" {
